input.new_string:
div_matrix <- matrix(NA_real_, nrow = n_permutations, ncol = n_samples)
for (p in cli::cli_progress_along(
  seq_len(n_permutations),
  name = "Computing sample-based accumulation curves"
)) {
  perm <- sample.int(n_samples)
  # Replace the previous per-step `colSums(otu_mat[perm[seq_len(k)], ])`
  # (O(n_samples^2 * n_taxa) per permutation) with one cumulative sum
  # across rows of the permuted matrix (O(n_samples * n_taxa) total).
  # `apply(., 2, cumsum)` returns a matrix of the same shape; row k is
  # then the pooled abundance after the first k samples — identical
  # values to the original code.
  pooled_mat <- apply(otu_mat[perm, , drop = FALSE], 2, cumsum)
  if (n_samples == 1L) {
    # apply() drops dim() when nrow == 1: restore the matrix shape
    # so the per-k indexing below stays uniform.
    pooled_mat <- matrix(pooled_mat, nrow = 1L)
  }
  for (k in seq_len(n_samples)) {
    pooled <- pooled_mat[k, ]
    pooled <- pooled[pooled > 0]
    div_matrix[p, k] <- divent::div_hill(
      pooled,
      q = q,
      as_numeric = TRUE,
      estimator = "naive",
      ...
    )
  }
}

