suppressMessages({
  library(rmarkdown)
})
out <- tempfile(fileext = ".html")
res <- tryCatch(
  rmarkdown::render(
    "vignettes/articles/timing.Rmd",
    output_file = out,
    quiet = TRUE
  ),
  error = function(e) e
)
if (inherits(res, "error")) {
  cat("RENDER FAILED:", conditionMessage(res), "\n")
  quit(status = 1)
} else {
  cat("RENDER OK:", res, "\n")
  cat("Size:", file.info(out)$size, "bytes\n")
}
EOF
Rscript /tmp/claude/render_timing.R > /tmp/claude/render_timing.log

cat > /tmp/claude/check_chunks.R <<'EOF'
files <- c(
  "vignettes/articles/accumulation-rarefaction.Rmd",
  "vignettes/articles/alpha-div.Rmd",
  "vignettes/articles/beta-div.Rmd",
  "vignettes/articles/timing.Rmd"
)
for (f in files) {
  out <- tempfile(fileext = ".R")
  res <- tryCatch(
    knitr::purl(f, output = out, quiet = TRUE, documentation = 0L),
    error = function(e) e
  )
  if (inherits(res, "error")) {
    cat("PURL FAIL:", f, "->", conditionMessage(res), "\n")
    next
  }
  parsed <- tryCatch(parse(file = out), error = function(e) e)
  if (inherits(parsed, "error")) {
    cat("PARSE FAIL:", f, "->", conditionMessage(parsed), "\n")
  } else {
    cat("OK:", f, "(", length(parsed), "top-level exprs)\n")
  }
}
EOF
Rscript /tmp/claude/check_chunks.R
